SELECT m.member_no, m.region_no, m.lastname, m.firstname, p.member_no AS payment_member_no FROM member AS m JOIN payment AS p ON m.member_no = p.member_no WHERE m.region_no = (SELECT leaf_1.region_no FROM (SELECT r.region_no, r.region_name, COUNT(p.provider_no) AS provider_count FROM region AS r JOIN provider AS p ON r.region_no = p.region_no GROUP BY r.region_no, r.region_name) AS leaf_1 ORDER BY leaf_1.provider_count DESC LIMIT 1)
